mapper.delete:
DELETE FROM COURSE
WHERE COURSE_ID = #{courseId}
AND USER_ID = #{userId}
AND IS_PUBLIC = 0

mapper.select:
SELECT C.COURSE_ID, C.USER_ID, C.COURSE_NAME, C.DISTANCE, C.TYPE, C.IS_PUBLIC, C.START_LOCATION, ST_AsText(C.START_POINT) AS START_POINT_WKT, ST_AsText(C.END_POINT) AS END_POINT_WKT, ST_AsText(C.ROUTE_LINE) AS ROUTE_LINE_WKT, R.AVG_RATING AS AVG_RATING
FROM COURSE C
LEFT JOIN ( SELECT COURSE_ID, AVG(REVIEW_RATING) AS AVG_RATING FROM REVIEW /* 필요시 여기서 삭제된 후기(IS_DELETE 등) 제외 조건 추가 */ GROUP BY COURSE_ID ) R ON R.COURSE_ID = C.COURSE_ID
AND C.IS_PUBLIC = 1
AND C.USER_ID = #{userId}
AND C.COURSE_NAME LIKE CONCAT('%', #{search.keyword}, '%')
AND C.DISTANCE >= #{search.minDistance}
AND C.DISTANCE <= #{search.maxDistance}
ORDER BY ST_Distance_Sphere( C.START_POINT, ST_GeomFromText(#{currentLocationWkt}, 4326) ) ASC
ORDER BY C.COURSE_ID DESC

mapper.update:
UPDATE COURSE
SET IS_PUBLIC = 1
WHERE COURSE_ID = #{courseId}
AND USER_ID = #{userId}
AND IS_PUBLIC = 0

mapper.delete:
DELETE FROM REVIEW
WHERE REVIEW_ID = #{reviewId}
AND USER_ID = #{userId}

mapper.update:
UPDATE REVIEW
SET REVIEW_CONTENT = #{reviewContent},
    REVIEW_RATING  = #{reviewRating}
WHERE REVIEW_ID   = #{reviewId}
  AND USER_ID     = #{userId}
  AND COURSE_ID   = #{courseId}

mapper.insert:
INSERT INTO REVIEW_IMAGE (
    REVIEW_ID,
    IMAGE
)
VALUES (
    #{reviewId},
    #{image}
)

mapper.select:
SELECT COUNT(1)
FROM REVIEW
WHERE COURSE_ID = #{courseId}

SELECT COUNT(1)
FROM REVIEW
WHERE WORKRECORD_ID = #{workRecordId}
